sys_script_include.script:
var AJAXUtils = Class.create();
AJAXUtils.prototype = Object.extendsObject(AbstractAjaxProcessor, {

    getPlugData: function() {
        // Get the sys_id from the request parameters
        var referenceSysId = this.getParameter('sysparm_sys_id');
        var gr = new GlideRecord('u_ev_plugs');
        if (gr.get(referenceSysId)) {
            var results = {
                "supply_input": gr.getValue("u_supply_input"),
                "charging_method": gr.getDisplayValue("u_charging_method"),
                "max_oc": gr.getValue("u_max_oc"),
                "max_op": gr.getValue("u_max_op"),
                "market_designation": gr.getDisplayValue("u_market_designation"),
                "manufacturer": gr.getDisplayValue("manufacturer"),
                "cost": gr.getValue("cost")
            };
            return JSON.stringify(results);
        } else {
            return null;
        }
    },

    getPlugName: function() {
        // Get the sys_id from the request parameters
        var referenceSysId = this.getParameter('sysparm_sys_id');
        var gr = new GlideRecord('u_ev_devices');
        if (gr.get(referenceSysId)) {
            var results = {
                "plug_type": gr.getValue("u_plug_type"),
            };
            return JSON.stringify(results);
        } else {
            return null;
        }
    },

    checkOpenIncidents: function() {
        // Get the sys_id from the request parameters
        var referenceSysId = this.getParameter('sysparm_sys_id');
        var gr = new GlideRecord('incident');
        gr.addEncodedQuery('active=true^cmdb_ciISNOTEMPTY^state!=6^category=ev_Box');
        gr.addQuery('cmdb_ci', referenceSysId);
        gr.setLimit(1);
        gr.query();

        if (gr.next()) {
            var results = {
                "ci": gr.getValue("cmdb_ci"),
                "incident_number": gr.getValue("number")
            };
            return JSON.stringify(results);
        } else {
            return null;
        }
    },

});
